#include <stdio.h>
#include <stdlib.h>
#define MAXN 100005
typedef struct Edge {
    int v, w;
    struct Edge* next;
} Edge;
Edge* edges[MAXN];
void addEdge(int u, int v, int w) {
    Edge* e = (Edge*) malloc(sizeof(Edge));
    e->v = v;
    e->w = w;
    e->next = edges[u];
    edges[u] = e;
}
void updateWeight(int u, int v, int w) {
    Edge* e = edges[u];
    while (e) {
        if (e->v == v) {
            e->w = w;
            return;
        }
        e = e->next;
    }
}
int dfs(int u, int v, int* visited) {
    if (u == v) return 0;
    visited[u] = 1;
    Edge* e = edges[u];
    int min = -1;
    while (e) {
        if (!visited[e->v]) {
            int w = dfs(e->v, v, visited);
            if (w != -1) {
                if (min == -1 || w + e->w < min) min = w + e->w;
            }
        }
        e = e->next;
    }
    return min;
}
int main() {
    int N, Q;
    scanf("%d", &N);
    for (int i = 0; i < N - 1; i++) {
        int u, v, w;
        scanf("%d %d %d", &u, &v, &w);
        addEdge(u, v, w);
        addEdge(v, u, w);
    }
    scanf("%d", &Q);
    for (int i = 0; i < Q; i++) {
        int type, u, v, w;
        scanf("%d %d %d", &type, &u, &v);
        if (type == 1) {
            scanf("%d", &w);
            updateWeight(u, v, w);
            updateWeight(v, u, w);
        } else {
            int* visited = (int*) malloc(sizeof(int) * N);
            for (int j = 0; j < N; j++) visited[j] = 0;
            printf("%d\n", dfs(u, v, visited));
            free(visited);
        }
    }
    return 0;
}

