import java.util.ArrayList;
import java.util.List;
import java.util.Scanner;
public class Main {
    static class Edge {
        int v, w;
        Edge(int v, int w) {
            this.v = v;
            this.w = w;
        }
    }
    static List<Edge>[] adj;
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        adj = new List[N];
        for (int i = 0; i < N; i++) adj[i] = new ArrayList<>();
        for (int i = 0; i < N - 1; i++) {
            int u = sc.nextInt() - 1;
            int v = sc.nextInt() - 1;
            int w = sc.nextInt();
            adj[u].add(new Edge(v, w));
            adj[v].add(new Edge(u, w));
        }
        int Q = sc.nextInt();
        for (int i = 0; i < Q; i++) {
            int type = sc.nextInt();
            int u = sc.nextInt() - 1;
            int v = sc.nextInt() - 1;
            if (type == 1) {
                int w = sc.nextInt();
                updateWeight(u, v, w);
                updateWeight(v, u, w);
            } else {
                boolean[] visited = new boolean[N];
                System.out.println(dfs(u, v, visited));
            }
        }
    }
    static void updateWeight(int u, int v, int w) {
        for (Edge e : adj[u]) {
            if (e.v == v) {
                e.w = w;
                return;
            }
        }
    }
    static int dfs(int u, int v, boolean[] visited) {
        if (u == v) return 0;
        visited[u] = true;
        int min = -1;
        for (Edge e : adj[u]) {
            if (!visited[e.v]) {
                int w = dfs(e.v, v, visited);
                if (w != -1) {
                    if (min == -1 || w + e.w < min) min = w + e.w;
                }
            }
        }
        return min;
    }
}

