    adj[u].push([v, w]);
    adj[v].push([u, w]);
}
function updateWeight(u, v, w) {
    for (let i = 0; i < adj[u].length; i++) {
        if (adj[u][i][0] === v) {
            adj[u][i][1] = w;
            return;
        }
    }
    for (let i = 0; i < adj[v].length; i++) {
        if (adj[v][i][0] === u) {
            adj[v][i][1] = w;
            return;
        }
    }
}
