    if (u === v) return 0;
    visited[u] = true;
    let min = -1;
    for (let e of adj[u]) {
        if (!visited[e[0]]) {
            let w = dfs(e[0], v, visited);
            if (w !== -1) {
                if (min === -1 || w + e[1] < min) min = w + e[1];
            }
        }
    }
    return min;
